const email = $json;

const dateFolderName = email.dateFolderName || email.receivedDate;
const clinicFolderName = email.clinicFolderName || email.clinic;

const safeDate = dateFolderName || new Date().toISOString().slice(0, 10);
const safeScriptId = email.scriptId || "UnknownScript";
const safePatientInitials = email.patientInitials || "UnknownInitials";

const fileName =
  email.fileName ||
  `${safeDate}-${safeScriptId}-${safePatientInitials}.pdf`;

return {
  json: {
    ...email,

    dateFolderName,
    clinicFolderName,
    fileName,

    // Keep these flat so every node after this can use $json directly
    DriveID: email.DriveID,
    AUMedOrderID: email.AUMedOrderID,
    CompletedOrdersID: email.CompletedOrdersID,
    OrderInProgressID: email.OrderInProgressID,
  }
};

